import React, { useState, useEffect } from "react";
import { rollDice } from "../../DiceRoller/Roll-script";

const DnDForm = () => {
  const [formData, setFormData] = useState({});
  const [sections, setSections] = useState([]);

  useEffect(() => {
    import(`../../../configs/dnd.json`)
      .then((config) => setSections(config.sections))
      .catch((err) => console.error("Error loading config:", err));
  }, []);

  const handleChange = (e, sectionName) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [sectionName]: {
        ...prev[sectionName],
        [name]: value,
      },
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log("DnD Character Data:", formData);
  };

  return (
    <form onSubmit={handleSubmit} className="character-form">
      {sections.map((section) => (
        <div key={section.name} className="character-form__section">
          <h3>{section.name}</h3>
          {section.fields.map((field) => (
            <div key={field.name} className="character-form__field">
              <label>{field.label}</label>
              <input
                name={field.name}
                type={field.type}
                value={formData[section.name]?.[field.name] || ""}
                onChange={(e) => handleChange(e, section.name)}
                required={field.required}
              />
            </div>
          ))}
        </div>
      ))}
      <button type="submit">Створити персонажа</button>
    </form>
  );
};

export default DnDForm;
